skip_64_end_session_request(<<_:64, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, TrUserData) -> dfp_read_field_def_end_session_request(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, TrUserData).

decode_msg_snapshot(Bin, TrUserData) ->
    dfp_read_field_def_snapshot(Bin,
                                0,
                                0,
                                0,
                                id(<<>>, TrUserData),
                                id('SESSION_STATUS_UNSPECIFIED', TrUserData),
                                id('SIDE_UNSPECIFIED', TrUserData),
                                id(0, TrUserData),
                                id(0, TrUserData),
                                id('SIDE_UNSPECIFIED', TrUserData),
                                id(<<>>, TrUserData),
                                id([], TrUserData),
                                id(<<>>, TrUserData),
                                TrUserData).

