skip_varint_snapshot(<<1:1, _:7, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData) -> skip_varint_snapshot(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData);
skip_varint_snapshot(<<0:1, _:7, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData) -> dfp_read_field_def_snapshot(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData).

skip_length_delimited_snapshot(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData) when N < 57 ->
    skip_length_delimited_snapshot(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData);
skip_length_delimited_snapshot(<<0:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData) ->
    Length = X bsl N + Acc,
    <<_:Length/binary, Rest2/binary>> = Rest,
    dfp_read_field_def_snapshot(Rest2, 0, 0, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData).

skip_group_snapshot(Bin, _, Z2, FNum, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData) ->
    {_, Rest} = read_group(Bin, FNum),
    dfp_read_field_def_snapshot(Rest, 0, Z2, FNum, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData).

skip_32_snapshot(<<_:32, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData) -> dfp_read_field_def_snapshot(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData).

skip_64_snapshot(<<_:64, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData) -> dfp_read_field_def_snapshot(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, F@_4, F@_5, F@_6, F@_7, F@_8, F@_9, TrUserData).

'd_enum_alekhine.session.v1.Side'(0) -> 'SIDE_UNSPECIFIED';
'd_enum_alekhine.session.v1.Side'(1) -> 'SIDE_WHITE';
'd_enum_alekhine.session.v1.Side'(2) -> 'SIDE_BLACK';
'd_enum_alekhine.session.v1.Side'(V) -> V.

'd_enum_alekhine.session.v1.SessionStatus'(0) -> 'SESSION_STATUS_UNSPECIFIED';
'd_enum_alekhine.session.v1.SessionStatus'(1) -> 'SESSION_STATUS_IN_PROGRESS';
'd_enum_alekhine.session.v1.SessionStatus'(2) -> 'SESSION_STATUS_FINISHED';
'd_enum_alekhine.session.v1.SessionStatus'(V) -> V.

read_group(Bin, FieldNum) ->
    {NumBytes, EndTagLen} = read_gr_b(Bin, 0, 0, 0, 0, FieldNum),
    <<Group:NumBytes/binary, _:EndTagLen/binary, Rest/binary>> = Bin,
    {Group, Rest}.

%% Like skipping over fields, but record the total length,
%% Each field is <(FieldNum bsl 3) bor FieldType> ++ <FieldValue>
%% Record the length because varints may be non-optimally encoded.
%%
%% Groups can be nested, but assume the same FieldNum cannot be nested
%% because group field numbers are shared with the rest of the fields
%% numbers. Thus we can search just for an group-end with the same
%% field number.
%%
%% (The only time the same group field number could occur would
%% be in a nested sub message, but then it would be inside a
%% length-delimited entry, which we skip-read by length.)
read_gr_b(<<1:1, X:7, Tl/binary>>, N, Acc, NumBytes, TagLen, FieldNum)
  when N < (32-7) ->
    read_gr_b(Tl, N+7, X bsl N + Acc, NumBytes, TagLen+1, FieldNum);
read_gr_b(<<0:1, X:7, Tl/binary>>, N, Acc, NumBytes, TagLen,
          FieldNum) ->
    Key = X bsl N + Acc,
    TagLen1 = TagLen + 1,
    case {Key bsr 3, Key band 7} of
        {FieldNum, 4} -> % 4 = group_end
            {NumBytes, TagLen1};
        {_, 0} -> % 0 = varint
            read_gr_vi(Tl, 0, NumBytes + TagLen1, FieldNum);
        {_, 1} -> % 1 = bits64
            <<_:64, Tl2/binary>> = Tl,
            read_gr_b(Tl2, 0, 0, NumBytes + TagLen1 + 8, 0, FieldNum);
        {_, 2} -> % 2 = length_delimited
            read_gr_ld(Tl, 0, 0, NumBytes + TagLen1, FieldNum);
        {_, 3} -> % 3 = group_start
            read_gr_b(Tl, 0, 0, NumBytes + TagLen1, 0, FieldNum);
        {_, 4} -> % 4 = group_end
            read_gr_b(Tl, 0, 0, NumBytes + TagLen1, 0, FieldNum);
        {_, 5} -> % 5 = bits32
            <<_:32, Tl2/binary>> = Tl,
            read_gr_b(Tl2, 0, 0, NumBytes + TagLen1 + 4, 0, FieldNum)
    end.

read_gr_vi(<<1:1, _:7, Tl/binary>>, N, NumBytes, FieldNum)
  when N < (64-7) ->
    read_gr_vi(Tl, N+7, NumBytes+1, FieldNum);
read_gr_vi(<<0:1, _:7, Tl/binary>>, _, NumBytes, FieldNum) ->
    read_gr_b(Tl, 0, 0, NumBytes+1, 0, FieldNum).

read_gr_ld(<<1:1, X:7, Tl/binary>>, N, Acc, NumBytes, FieldNum)
  when N < (64-7) ->
    read_gr_ld(Tl, N+7, X bsl N + Acc, NumBytes+1, FieldNum);
read_gr_ld(<<0:1, X:7, Tl/binary>>, N, Acc, NumBytes, FieldNum) ->
    Len = X bsl N + Acc,
    NumBytes1 = NumBytes + 1,
    <<_:Len/binary, Tl2/binary>> = Tl,
    read_gr_b(Tl2, 0, 0, NumBytes1 + Len, 0, FieldNum).

merge_msgs(Prev, New, MsgName) when is_atom(MsgName) -> merge_msgs(Prev, New, MsgName, []).

merge_msgs(Prev, New, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        create_session_request -> merge_msg_create_session_request(Prev, New, TrUserData);
        player_ref -> merge_msg_player_ref(Prev, New, TrUserData);
        game_ref -> merge_msg_game_ref(Prev, New, TrUserData);
        end_session_request -> merge_msg_end_session_request(Prev, New, TrUserData);
        snapshot -> merge_msg_snapshot(Prev, New, TrUserData)
    end.

-compile({nowarn_unused_function,merge_msg_create_session_request/3}).
merge_msg_create_session_request(PMsg, NMsg, _) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{game_id := NFgame_id}} -> S1#{game_id => NFgame_id};
             {#{game_id := PFgame_id}, _} -> S1#{game_id => PFgame_id};
             _ -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{white_id := NFwhite_id}} -> S2#{white_id => NFwhite_id};
             {#{white_id := PFwhite_id}, _} -> S2#{white_id => PFwhite_id};
             _ -> S2
         end,
    S4 = case {PMsg, NMsg} of
             {_, #{black_id := NFblack_id}} -> S3#{black_id => NFblack_id};
             {#{black_id := PFblack_id}, _} -> S3#{black_id => PFblack_id};
             _ -> S3
         end,
    S5 = case {PMsg, NMsg} of
             {_, #{initial_ms := NFinitial_ms}} -> S4#{initial_ms => NFinitial_ms};
             {#{initial_ms := PFinitial_ms}, _} -> S4#{initial_ms => PFinitial_ms};
             _ -> S4
         end,
    S6 = case {PMsg, NMsg} of
             {_, #{increment_ms := NFincrement_ms}} -> S5#{increment_ms => NFincrement_ms};
             {#{increment_ms := PFincrement_ms}, _} -> S5#{increment_ms => PFincrement_ms};
             _ -> S5
         end,
    case {PMsg, NMsg} of
        {_, #{grace_ms := NFgrace_ms}} -> S6#{grace_ms => NFgrace_ms};
        {#{grace_ms := PFgrace_ms}, _} -> S6#{grace_ms => PFgrace_ms};
        _ -> S6
    end.

-compile({nowarn_unused_function,merge_msg_player_ref/3}).
merge_msg_player_ref(PMsg, NMsg, _) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{game_id := NFgame_id}} -> S1#{game_id => NFgame_id};
             {#{game_id := PFgame_id}, _} -> S1#{game_id => PFgame_id};
             _ -> S1
         end,
    case {PMsg, NMsg} of
        {_, #{player_id := NFplayer_id}} -> S2#{player_id => NFplayer_id};
        {#{player_id := PFplayer_id}, _} -> S2#{player_id => PFplayer_id};
        _ -> S2
    end.

-compile({nowarn_unused_function,merge_msg_game_ref/3}).
merge_msg_game_ref(PMsg, NMsg, _) ->
    S1 = #{},
    case {PMsg, NMsg} of
        {_, #{game_id := NFgame_id}} -> S1#{game_id => NFgame_id};
        {#{game_id := PFgame_id}, _} -> S1#{game_id => PFgame_id};
        _ -> S1
    end.

-compile({nowarn_unused_function,merge_msg_end_session_request/3}).
merge_msg_end_session_request(PMsg, NMsg, _) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{game_id := NFgame_id}} -> S1#{game_id => NFgame_id};
             {#{game_id := PFgame_id}, _} -> S1#{game_id => PFgame_id};
             _ -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{winner := NFwinner}} -> S2#{winner => NFwinner};
             {#{winner := PFwinner}, _} -> S2#{winner => PFwinner};
             _ -> S2
         end,
    case {PMsg, NMsg} of
        {_, #{reason := NFreason}} -> S3#{reason => NFreason};
        {#{reason := PFreason}, _} -> S3#{reason => PFreason};
        _ -> S3
    end.

-compile({nowarn_unused_function,merge_msg_snapshot/3}).
merge_msg_snapshot(PMsg, NMsg, TrUserData) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{game_id := NFgame_id}} -> S1#{game_id => NFgame_id};
             {#{game_id := PFgame_id}, _} -> S1#{game_id => PFgame_id};
             _ -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{status := NFstatus}} -> S2#{status => NFstatus};
             {#{status := PFstatus}, _} -> S2#{status => PFstatus};
             _ -> S2
         end,
    S4 = case {PMsg, NMsg} of
             {_, #{turn := NFturn}} -> S3#{turn => NFturn};
             {#{turn := PFturn}, _} -> S3#{turn => PFturn};
             _ -> S3
         end,
    S5 = case {PMsg, NMsg} of
             {_, #{white_ms := NFwhite_ms}} -> S4#{white_ms => NFwhite_ms};
             {#{white_ms := PFwhite_ms}, _} -> S4#{white_ms => PFwhite_ms};
             _ -> S4
         end,
    S6 = case {PMsg, NMsg} of
             {_, #{black_ms := NFblack_ms}} -> S5#{black_ms => NFblack_ms};
             {#{black_ms := PFblack_ms}, _} -> S5#{black_ms => PFblack_ms};
             _ -> S5
         end,
    S7 = case {PMsg, NMsg} of
             {_, #{winner := NFwinner}} -> S6#{winner => NFwinner};
             {#{winner := PFwinner}, _} -> S6#{winner => PFwinner};
             _ -> S6
         end,
    S8 = case {PMsg, NMsg} of
             {_, #{reason := NFreason}} -> S7#{reason => NFreason};
             {#{reason := PFreason}, _} -> S7#{reason => PFreason};
             _ -> S7
         end,
    S9 = case {PMsg, NMsg} of
             {#{spectators := PFspectators}, #{spectators := NFspectators}} -> S8#{spectators => 'erlang_++'(PFspectators, NFspectators, TrUserData)};
             {_, #{spectators := NFspectators}} -> S8#{spectators => NFspectators};
             {#{spectators := PFspectators}, _} -> S8#{spectators => PFspectators};
             {_, _} -> S8
         end,
    case {PMsg, NMsg} of
        {_, #{error := NFerror}} -> S9#{error => NFerror};
        {#{error := PFerror}, _} -> S9#{error => PFerror};
        _ -> S9
    end.


verify_msg(Msg, MsgName) when is_atom(MsgName) -> verify_msg(Msg, MsgName, []).

verify_msg(Msg, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        create_session_request -> v_msg_create_session_request(Msg, [MsgName], TrUserData);
        player_ref -> v_msg_player_ref(Msg, [MsgName], TrUserData);
        game_ref -> v_msg_game_ref(Msg, [MsgName], TrUserData);
        end_session_request -> v_msg_end_session_request(Msg, [MsgName], TrUserData);
        snapshot -> v_msg_snapshot(Msg, [MsgName], TrUserData);
        _ -> mk_type_error(not_a_known_message, Msg, [])
    end.


-compile({nowarn_unused_function,v_msg_create_session_request/3}).
-dialyzer({nowarn_function,v_msg_create_session_request/3}).
v_msg_create_session_request(#{} = M, Path, TrUserData) ->
    case M of
        #{game_id := F1} -> v_type_string(F1, [game_id | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{white_id := F2} -> v_type_string(F2, [white_id | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{black_id := F3} -> v_type_string(F3, [black_id | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{initial_ms := F4} -> v_type_int64(F4, [initial_ms | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{increment_ms := F5} -> v_type_int64(F5, [increment_ms | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{grace_ms := F6} -> v_type_int64(F6, [grace_ms | Path], TrUserData);
        _ -> ok
    end,
    lists:foreach(fun (game_id) -> ok;
                      (white_id) -> ok;
                      (black_id) -> ok;
                      (initial_ms) -> ok;
                      (increment_ms) -> ok;
                      (grace_ms) -> ok;
                      (OtherKey) -> mk_type_error({extraneous_key, OtherKey}, M, Path)
                  end,
                  maps:keys(M)),
    ok;
v_msg_create_session_request(M, Path, _TrUserData) when is_map(M) -> mk_type_error({missing_fields, [] -- maps:keys(M), create_session_request}, M, Path);
v_msg_create_session_request(X, Path, _TrUserData) -> mk_type_error({expected_msg, create_session_request}, X, Path).

