-compile({nowarn_unused_function,v_msg_snapshot/3}).
-dialyzer({nowarn_function,v_msg_snapshot/3}).
v_msg_snapshot(#{} = M, Path, TrUserData) ->
    case M of
        #{game_id := F1} -> v_type_string(F1, [game_id | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{status := F2} -> 'v_enum_alekhine.session.v1.SessionStatus'(F2, [status | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{turn := F3} -> 'v_enum_alekhine.session.v1.Side'(F3, [turn | Path], TrUserData);
